import { statfs } from 'node:fs/promises';
import { resolve } from 'node:path';
import { execa } from 'execa';
import fs from 'fs-extra';
import { simpleGit } from 'simple-git';
import { loadBrowserConfig } from './config/load.js';
import { firefoxCompatibility } from './firefox/compatibility.js';
import { generateMozconfig } from './firefox/mozconfig.js';
import { projectPaths } from './project.js';
import { readFirefoxLock } from './source.js';
import { validateProjectIdentity, validateProjectPatches } from './apply.js';
const { pathExists, readFile } = fs;
async function commandCheck(name, command, args, fix) {
    try {
        const result = await execa(command, args);
        return { name, ok: true, detail: result.stdout.split('\n')[0] ?? 'available' };
    }
    catch {
        return { name, ok: false, detail: `${command} not available`, fix };
    }
}
export async function doctorProject(cwd = process.cwd()) {
    const config = await loadBrowserConfig(cwd);
    const paths = await projectPaths(cwd);
    const pythonCommand = process.platform === 'win32' ? 'python' : 'python3';
    let python = await commandCheck('Python', pythonCommand, ['--version'], 'Run `geckokit setup` or install Python 3.9+.');
    if (!python.ok && process.platform === 'win32') {
        python = await commandCheck('Python', 'py', ['-3', '--version'], 'Install native Python 3.9–3.12 or MozillaBuild.');
    }
    const pythonVersion = /Python (\d+)\.(\d+)/.exec(python.detail);
    if (python.ok && (!pythonVersion || Number(pythonVersion[1]) !== 3 || Number(pythonVersion[2]) < 9 || Number(pythonVersion[2]) > 12)) {
        Object.assign(python, { ok: false, fix: 'Use Python 3.9 through 3.12 for supported Firefox releases.' });
    }
    const rust = await commandCheck('Rust', 'rustc', ['--version'], 'Run `geckokit setup` or install Rust with rustup.');
    const git = await commandCheck('Git', 'git', ['--version'], 'Install Git, then run `geckokit setup`.');
    const compiler = process.platform === 'darwin'
        ? await commandCheck('C/C++ compiler', 'xcode-select', ['-p'], 'Install Xcode command-line tools, then run `geckokit setup`.')
        : process.platform === 'win32'
            ? await commandCheck('C/C++ compiler', 'where.exe', ['cl.exe'], 'Install MozillaBuild and Visual Studio Build Tools, then run `geckokit setup`.')
            : await commandCheck('C/C++ compiler', 'cc', ['--version'], 'Install Ubuntu build-essential, then run `geckokit setup`.');
    const checks = [
        Number(process.versions.node.split('.')[0]) >= 22
            ? { name: 'Node', ok: true, detail: process.version }
            : { name: 'Node', ok: false, detail: process.version, fix: 'Install Node.js 22 or newer.' },
        python,
        rust,
        git,
        compiler,
    ];
    const disk = await statfs(paths.projectDirectory);
    const freeGiB = Number(disk.bavail * disk.bsize) / 1024 ** 3;
    const neededGiB = config.build.mode === 'full' ? 40 : 10;
    checks.push(freeGiB >= neededGiB
        ? { name: 'Disk space', ok: true, detail: `${freeGiB.toFixed(1)} GiB free` }
        : { name: 'Disk space', ok: false, detail: `${freeGiB.toFixed(1)} GiB free`, fix: `Free at least ${neededGiB} GiB.` });
    const mach = resolve(paths.firefoxSource, 'mach');
    const sourceExists = await pathExists(mach) && await simpleGit(paths.firefoxSource).checkIsRepo().catch(() => false);
    checks.push(sourceExists
        ? { name: 'Firefox source', ok: true, detail: paths.firefoxSource }
        : { name: 'Firefox source', ok: false, detail: 'Missing or invalid checkout', fix: 'Run `geckokit setup`.' });
    checks.push(python.ok && rust.ok && git.ok && compiler.ok
        ? { name: 'Bootstrap', ok: true, detail: 'Core toolchains available' }
        : { name: 'Bootstrap', ok: false, detail: 'Core toolchain missing', fix: 'Run `geckokit setup`, then follow mach bootstrap instructions.' });
    const patchDirectory = resolve(paths.projectDirectory, config.patches.directory);
    let patchesValid = false;
    if (sourceExists && await pathExists(patchDirectory)) {
        patchesValid = await validateProjectPatches(cwd).then(() => true).catch(() => false);
    }
    checks.push(patchesValid
        ? { name: 'Patch compatibility', ok: true, detail: 'Ordered patch stack applies cleanly' }
        : { name: 'Patch compatibility', ok: false, detail: 'Cannot validate patch stack', fix: sourceExists ? 'Fix or remove the first incompatible patch.' : 'Run `geckokit setup`.' });
    let lock;
    try {
        lock = await readFirefoxLock(cwd);
    }
    catch {
        lock = undefined;
    }
    const brandingBase = lock
        ? resolve(paths.firefoxSource, firefoxCompatibility(lock.version).brandingBase)
        : undefined;
    const brandingReady = !config.branding.enabled || (brandingBase !== undefined &&
        await pathExists(brandingBase) &&
        await pathExists(resolve(paths.projectDirectory, config.branding.directory, 'configure.sh')));
    checks.push(brandingReady
        ? { name: 'Branding', ok: true, detail: config.branding.enabled ? 'Custom branding ready' : 'Disabled' }
        : { name: 'Branding', ok: false, detail: 'Branding base or configure.sh missing', fix: 'Run `geckokit setup` and restore branding/configure.sh.' });
    const identityReady = sourceExists && lock !== undefined &&
        await validateProjectIdentity(cwd).then(() => true).catch(() => false);
    checks.push(identityReady
        ? { name: 'Browser identity', ok: true, detail: 'Source matches configured vendor and application ID' }
        : { name: 'Browser identity', ok: false, detail: 'Source identity is missing or stale', fix: 'Run `geckokit apply` or any build command.' });
    const mozconfigPath = resolve(paths.projectDirectory, 'mozconfig');
    const expectedMozconfig = lock ? generateMozconfig(config, lock.version) : undefined;
    const mozconfigReady = expectedMozconfig !== undefined &&
        await readFile(mozconfigPath, 'utf8').then((value) => value === expectedMozconfig).catch(() => false);
    checks.push(mozconfigReady
        ? { name: 'mozconfig', ok: true, detail: 'Matches locked Firefox version' }
        : { name: 'mozconfig', ok: false, detail: 'Missing or stale', fix: 'Run `geckokit setup`.' });
    const externalMozconfig = process.env.MOZCONFIG;
    checks.push(!externalMozconfig || resolve(externalMozconfig) === mozconfigPath
        ? { name: 'Environment variables', ok: true, detail: 'No conflicting MOZCONFIG' }
        : { name: 'Environment variables', ok: false, detail: `MOZCONFIG=${externalMozconfig}`, fix: 'Unset MOZCONFIG; GeckoKit supplies the project mozconfig.' });
    return checks;
}
